import { useState, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import "./Auth.css";

export default function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPwd, setShowPwd] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [loginMode, setLoginMode] = useState("password"); // "password" or "otp"
  const [otpSent, setOtpSent] = useState(false);
  const [otp, setOtp] = useState("");
  const [otpLoading, setOtpLoading] = useState(false);
  const [cursorPos, setCursorPos] = useState({ x: -999, y: -999 });
  const { login } = useAuth();
  const navigate = useNavigate();

  // Cursor glow effect
  useEffect(() => {
    const handle = (e) => setCursorPos({ x: e.clientX, y: e.clientY });
    window.addEventListener("mousemove", handle);
    return () => window.removeEventListener("mousemove", handle);
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true); setError("");
    try {
      const res = await fetch("http://localhost:5782/api/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.message || "Invalid credentials");
      login(data.user, data.token);
      navigate("/");
    } catch (err) { setError(err.message || "Invalid credentials"); }
    setLoading(false);
  };

  const handleSendOTP = async () => {
    if (!email) { setError("Enter your email first"); return; }
    setOtpLoading(true); setError("");
    try {
      const res = await fetch("http://localhost:5782/api/auth/send-otp", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.message);
      setOtpSent(true);
    } catch (err) { setError(err.message); }
    setOtpLoading(false);
  };

  const handleVerifyOTP = async (e) => {
    e.preventDefault();
    setLoading(true); setError("");
    try {
      const res = await fetch("http://localhost:5782/api/auth/verify-otp", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, otp })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.message);
      login(data.user, data.token);
      navigate("/");
    } catch (err) { setError(err.message); }
    setLoading(false);
  };

  return (
    <div className="auth-page">
      {/* Cursor glow */}
      <div className="cursor-glow" style={{ left: cursorPos.x, top: cursorPos.y }} />

      <div className="auth-bg">
        <div className="auth-orb orb1" />
        <div className="auth-orb orb2" />
        <div className="auth-orb orb3" />
        <div className="auth-grid" />
      </div>

      <div className="auth-container">
        {/* Left hero */}
        <div className="auth-left">
          <div className="auth-logo-wrap">
            <div className="auth-logo">
              <svg viewBox="0 0 40 40" fill="none">
                <circle cx="14" cy="13" r="7" fill="url(#lg1)"/>
                <circle cx="26" cy="13" r="7" fill="url(#lg2)" opacity="0.9"/>
                <circle cx="20" cy="26" r="7" fill="url(#lg3)" opacity="0.95"/>
                <defs>
                  <linearGradient id="lg1" x1="0" y1="0" x2="1" y2="1"><stop stopColor="#a78bfa"/><stop offset="1" stopColor="#7c3aed"/></linearGradient>
                  <linearGradient id="lg2" x1="0" y1="0" x2="1" y2="1"><stop stopColor="#60a5fa"/><stop offset="1" stopColor="#2563eb"/></linearGradient>
                  <linearGradient id="lg3" x1="0" y1="0" x2="1" y2="1"><stop stopColor="#818cf8"/><stop offset="1" stopColor="#4f46e5"/></linearGradient>
                </defs>
              </svg>
            </div>
            <span className="auth-brand">PeerSync</span>
          </div>

          <h1 className="auth-hero-title">
            Chat that<br/><span>syncs with you</span>
          </h1>
          <p className="auth-hero-sub">
            Real-time messaging, status updates, groups and more — all in one place. Private. Fast. Free.
          </p>

          <div className="auth-features">
            {[
              ["💬", "Real-time messaging with reactions"],
              ["📸", "Status updates like stories"],
              ["👥", "Group chats with polls"],
              ["🔒", "Privacy controls for everything"],
            ].map(([icon, text]) => (
              <div className="auth-feature" key={text}>
                <div className="auth-feature-icon">{icon}</div>
                <span className="auth-feature-text">{text}</span>
              </div>
            ))}
          </div>

          <div className="auth-trust">
            <div className="auth-trust-item">🔒 End-to-end encrypted</div>
            <div className="auth-trust-item">⚡ &lt;100ms messaging</div>
            <div className="auth-trust-item">🌎 Free forever</div>
          </div>
        </div>

        {/* Right card */}
        <div className="auth-right">
          <div className="auth-card">
            <h2 className="auth-card-title">Welcome back 👋</h2>
            <p className="auth-card-sub">Sign in to your PeerSync account</p>

            {error && <div className="auth-error">⚠️ {error}</div>}

            {/* Toggle buttons */}
            <div style={{display:"flex",gap:"6px",marginBottom:"20px",background:"#f3f4f6",borderRadius:"12px",padding:"4px"}}>
              <button type="button"
                onClick={() => { setLoginMode("password"); setOtpSent(false); setOtp(""); setError(""); }}
                style={{flex:1,padding:"9px",borderRadius:"9px",border:"none",fontSize:"13px",fontWeight:"700",cursor:"pointer",fontFamily:"inherit",
                  background: loginMode === "password" ? "#fff" : "transparent",
                  color: loginMode === "password" ? "#064e3b" : "#9ca3af",
                  boxShadow: loginMode === "password" ? "0 1px 4px rgba(0,0,0,0.1)" : "none",
                  transition:"all 0.2s"
                }}>🔒 Password</button>
              <button type="button"
                onClick={() => { setLoginMode("otp"); setOtpSent(false); setOtp(""); setError(""); }}
                style={{flex:1,padding:"9px",borderRadius:"9px",border:"none",fontSize:"13px",fontWeight:"700",cursor:"pointer",fontFamily:"inherit",
                  background: loginMode === "otp" ? "#fff" : "transparent",
                  color: loginMode === "otp" ? "#064e3b" : "#9ca3af",
                  boxShadow: loginMode === "otp" ? "0 1px 4px rgba(0,0,0,0.1)" : "none",
                  transition:"all 0.2s"
                }}>📧 Email OTP</button>
            </div>

            {loginMode === "password" ? (
              <form className="auth-form" onSubmit={handleSubmit}>
                <div className="auth-field">
                  <label className="auth-label">Email address</label>
                  <div className="auth-input-wrap">
                    <span className="auth-input-icon">📧</span>
                    <input className="auth-input" type="email" placeholder="your@email.com"
                      value={email} onChange={e => setEmail(e.target.value)} required />
                  </div>
                </div>
                <div className="auth-field">
                  <label className="auth-label">Password</label>
                  <div className="auth-input-wrap">
                    <span className="auth-input-icon">🔒</span>
                    <input className="auth-input" type={showPwd ? "text" : "password"}
                      placeholder="Enter your password"
                      value={password} onChange={e => setPassword(e.target.value)} required />
                    <button type="button" className="auth-eye" onClick={() => setShowPwd(!showPwd)}>
                      {showPwd ? "🙈" : "👁️"}
                    </button>
                  </div>
                </div>
                <button className="auth-btn" type="submit" disabled={loading}>
                  {loading ? <><span className="auth-spinner" /> Signing in...</> : <>Sign In →</>}
                </button>
              </form>
            ) : (
              <form className="auth-form" onSubmit={otpSent ? handleVerifyOTP : (e) => { e.preventDefault(); handleSendOTP(); }}>
                <div className="auth-field">
                  <label className="auth-label">Email address</label>
                  <div className="auth-input-wrap">
                    <span className="auth-input-icon">📧</span>
                    <input className="auth-input" type="email" placeholder="your@email.com"
                      value={email} onChange={e => setEmail(e.target.value)} required disabled={otpSent} />
                  </div>
                </div>
                {otpSent && (
                  <div className="auth-field">
                    <label className="auth-label">Enter OTP sent to your email</label>
                    <div className="auth-input-wrap">
                      <span className="auth-input-icon">🔢</span>
                      <input className="auth-input" type="text" placeholder="6-digit code"
                        value={otp} onChange={e => setOtp(e.target.value.replace(/\D/g,"").slice(0,6))}
                        maxLength={6} required style={{letterSpacing:"8px",fontSize:"20px",fontWeight:"700"}} />
                    </div>
                    <button type="button" onClick={() => { setOtpSent(false); setOtp(""); }}
                      style={{background:"none",border:"none",color:"#10b981",fontSize:"12px",fontWeight:"600",cursor:"pointer",marginTop:"4px",padding:0}}>
                      ↩ Change email / Resend
                    </button>
                  </div>
                )}
                <button className="auth-btn" type="submit" disabled={loading || otpLoading}>
                  {loading || otpLoading
                    ? <><span className="auth-spinner" /> {otpSent ? "Verifying..." : "Sending OTP..."}</>
                    : otpSent ? <>✓ Verify OTP</> : <>📧 Send OTP</>
                  }
                </button>
                {otpSent && (
                  <p style={{textAlign:"center",fontSize:"12px",color:"#9ca3af",marginTop:"4px"}}>
                    ✉️ Check your inbox — OTP expires in 10 minutes
                  </p>
                )}
              </form>
            )}

            <p className="auth-switch">
              Don't have an account? <Link to="/register">Create one free</Link>
            </p>

            <div className="auth-footer">
              © 2026 PeerSync &nbsp;
              <a href="/privacy" onClick={e=>{e.preventDefault();window.location.href='/privacy'}}>Privacy</a>
              <a href="/terms" onClick={e=>{e.preventDefault();window.location.href='/terms'}}>Terms</a>
              <a href="/security-info" onClick={e=>{e.preventDefault();window.location.href='/security-info'}}>Security</a>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
